INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'aurora'), 'R-1', 'r-1', 'One Family Dwelling District', 'The R-1 Single Family Residence District is established to preserve and maintain existing single family areas and permit the continued development of residential uses, primarily in areas where public utilities are not readily available. This district promotes and preserves safe and attractive low-density, single-family residences.', 36, NULL, 5000, NULL, 15, 25, 5, 'Two (2) off-street parking spaces per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'r-1' AND z.city_id = (SELECT id FROM cities WHERE slug = 'aurora') AND pu.name IN ('Single Family Detached Dwellings', 'Home occupations', 'Parks and open space', 'Places of worship', 'Schools, public and private') ON CONFLICT DO NOTHING;
