INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'aurora'), 'R-5', 'r-5', 'Multiple-Family Dwelling District', 'The R-5 Multiple-family Dwelling District is established to develop a wide range of quality housing opportunities, allowing for quality rental type dwelling units within developments that establish and maintain a safe and secure living environment. It provides for a range of low-density residential accommodations and lifestyles, representing a compatible mixture of single-family detached, two-family, and multiple-family dwellings.', NULL, NULL, 15000, NULL, NULL, NULL, NULL, 'One (1) off-street parking space per dwelling unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
